def main():
    counts = {"A": 0, "B": 0, "C": 0, "F": 0}
    with open("scores.txt") as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            score = int(line)
            if score >= 90:
                counts["A"] += 1
            elif score >= 80:
                counts["B"] += 1
            elif score >= 70:
                counts["C"] += 1
            else:
                counts["F"] += 1

    for letter in ["A", "B", "C", "F"]:
        if counts[letter] > 0:
            print(f"{letter} {counts[letter]}")


if __name__ == "__main__":
    main()

